/**
 * Helper class for Deque implementation required for 0-1 BFS
 * Although a standard array can simulate a deque, a proper structure ensures O(1) operations.
 */
class Deque {
    constructor() {
        this.items = [];
    }

    pushFront(item) {
        this.items.unshift(item);
    }

    pushBack(item) {
        this.items.push(item);
    }

    popFront() {
        if (this.isEmpty()) return undefined;
        return this.items.shift();
    }

    popBack() {
        if (this.isEmpty()) return undefined;
        return this.items.pop();
    }

    isEmpty() {
        return this.items.length === 0;
    }
}

/**
 * Checks if a path exists from source to target using at most k heavy edges 
 * given a specific threshold. Uses 0-1 BFS.
 * 
 * @param {number} n Number of nodes
 * @param {Array<Array<number>>} edges List of [u, v, w]
 * @param {number} source Starting node
 * @param {number} target Ending node
 * @param {number} k Max allowed heavy edges
 * @param {number} threshold The weight threshold
 * @returns {boolean} True if an effective path exists, false otherwise.
 */
function canReach(n, edges, source, target, k, threshold) {
    if (source === target) return true;

    // Build adjacency list: adj[u] = [[v1, w1], [v2, w2], ...]
    const adj = Array(n).fill(0).map(() => []);
    for (const [u, v, w] of edges) {
        adj[u].push([v, w]);
        adj[v].push([u, w]);
    }

    // MinHeavy[i] stores the minimum number of heavy edges required to reach node i.
    const minHeavy = Array(n).fill(Infinity);

    // Use a Deque for 0-1 BFS: stores node indices
    const deque = new Deque();

    minHeavy[source] = 0;
    deque.pushFront(source);

    while (!deque.isEmpty()) {
        const u = deque.popFront();
        const currentHeavyCount = minHeavy[u];

        if (u === target) {
            // Optimization: Since 0-1 BFS finds shortest paths layer by layer (in terms of 0/1 weight), 
            // if we reach the target, we found the minimum heavy count.
            // We still need to process until the queue is empty to ensure all paths are explored 
            // if we wanted the absolute minimum, but since we only care if it's <= k, 
            // and paths are non-negative, we can stop early if the current path is good.
            // However, let's complete the BFS for correctness unless performance is critical.
        }

        for (const [v, w] of adj[u]) {
            // Cost: 1 if heavy (w > threshold), 0 if light (w <= threshold)
            const cost = (w > threshold) ? 1 : 0;
            const newHeavyCount = currentHeavyCount + cost;

            if (newHeavyCount < minHeavy[v]) {
                minHeavy[v] = newHeavyCount;

                if (cost === 0) {
                    // 0 weight edge, prioritize (push to front)
                    deque.pushFront(v);
                } else {
                    // 1 weight edge, append (push to back)
                    deque.pushBack(v);
                }
            }
        }
    }

    return minHeavy[target] <= k;
}


/**
 * Finds the minimum threshold such that a path exists from source to target 
 * with at most k heavy edges.
 * 
 * @param {number} n Number of nodes
 * @param {Array<Array<number>>} edges List of [u, v, w]
 * @param {number} source Starting node
 * @param {number} target Ending node
 * @param {number} k Max allowed heavy edges
 * @returns {number} Minimum threshold, or -1 if no path exists even with high threshold.
 */
function solve(n, edges, source, target, k) {
    // Handle trivial case: Source equals Target
    if (source === target) {
        return 0;
    }

    // 1. Determine search space for threshold T.
    // The weights W are up to 10^9. T can range from 0 up to max(W).
    // We search in [L, R].
    let L = 0;
    // A safe upper bound is max weight + 1. Since max weight is 10^9, 10^9 + 1 is sufficient.
    let R = 1000000000 + 1; 
    let ans = -1;

    // 2. Binary Search on the threshold
    while (L <= R) {
        const M = L + Math.floor((R - L) / 2);

        if (canReach(n, edges, source, target, k, M)) {
            // Threshold M works. Record it and try smaller thresholds.
            ans = M;
            R = M - 1;
        } else {
            // Threshold M is too restrictive (not enough edges are light). 
            // Must increase the threshold to make more edges light.
            L = M + 1;
        }
    }

    return ans;
}

