    if (source == target) return true

    // Adjacency list: adj[u] = List of [v, w]
    val adj = Array(n) { mutableListOf<Pair<Int, Long>>() }
    for (edge in edges) {
        val u = edge[0].toInt()
        val v = edge[1].toInt()
        val w = edge[2]
        adj[u].add(Pair(v, w))
        adj[v].add(Pair(u, w))
    }

    // MinHeavy[i] stores the minimum number of heavy edges required to reach node i.
    // Since N <= 1000, maximum heavy count is < 1000. We use a large constant for infinity.
    val INF = n + 1 
    val minHeavy = IntArray(n) { INF }

