        val u = deque.removeFirst()
        val currentHeavyCount = minHeavy[u]

        if (u == target.toInt()) {
            // We don't necessarily stop here because we might find a path with fewer heavy edges 
            // later if we weren't using 0-1 BFS, but since 0-1 BFS guarantees finding the minimum 
            // cost first, if we reach target, we found the minimum required heavy count.
            // However, the loop naturally finds the minimum for all nodes before they are popped,
