 * with at most k heavy edges.
 * 
 * @param {number} n Number of nodes
 * @param {Array<Array<number>>} edges List of [u, v, w]
 * @param {number} source Starting node
 * @param {number} target Ending node
 * @param {number} k Max allowed heavy edges
 * @returns {number} Minimum threshold, or -1 if no path exists even with high threshold.
 */
function solve(n, edges, source, target, k) {
    // Handle trivial case: Source equals Target
    if (source === target) {
        return 0;
    }

    // 1. Determine search space for threshold T.
    // The weights W are up to 10^9. T can range from 0 up to max(W).
    // We search in [L, R].
    let L = 0;
    // A safe upper bound is max weight + 1. Since max weight is 10^9, 10^9 + 1 is sufficient.
    let R = 1000000000 + 1; 
    let ans = -1;

    // 2. Binary Search on the threshold
    while (L <= R) {
        const M = L + Math.floor((R - L) / 2);

        if (canReach(n, edges, source, target, k, M)) {
            // Threshold M works. Record it and try smaller thresholds.
            ans = M;
            R = M - 1;
        } else {
            // Threshold M is too restrictive (not enough edges are light). 
            // Must increase the threshold to make more edges light.
            L = M + 1;
        }
    }

    return ans;
}

