/**
 * Helper class for Deque implementation required for 0-1 BFS
 * Although a standard array can simulate a deque, a proper structure ensures O(1) operations.
 */
class Deque {
    constructor() {
        this.items = [];
    }

    pushFront(item) {
        this.items.unshift(item);
    }

    pushBack(item) {
        this.items.push(item);
    }

    popFront() {
        if (this.isEmpty()) return undefined;
        return this.items.shift();
    }

    popBack() {
        if (this.isEmpty()) return undefined;
        return this.items.pop();
    }

    isEmpty() {
        return this.items.length === 0;
    }
}

